INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$No-account game rooms$q$, $q$Teachers open a session and students join instantly with a nickname; no email address or sign-up is ever required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Live buzzer mechanic$q$, $q$Students race to tap a virtual buzzer, and the fastest player is flagged to the host to answer the question out loud.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Automatic scoring and leaderboard$q$, $q$Points are awarded when the teacher marks an answer correct, and a live ranking or podium updates in real time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Custom avatars and nicknames$q$, $q$Players choose or upload an avatar and a display name to personalize their presence in the game.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Works on any device$q$, $q$Runs entirely in a browser tab, so it works on classroom tablets, phones, laptops, and interactive whiteboards.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$GDPR-friendly hosting$q$, $q$Session data is hosted on Infomaniak's Swiss infrastructure and is not retained beyond the game session.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Remote or in-person play$q$, $q$Supports both face-to-face classroom games and fully remote sessions over a shared link.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Part of the La Digitale suite$q$, $q$Integrates conceptually with sibling tools like Digistorm and Digipad for broader classroom activity planning.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Completely free with no paid tier or hidden limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$No account creation required for teachers or students$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Extremely fast to set up - a game can start in under a minute$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Privacy-respecting, GDPR-compliant, ad-free design$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$No built-in question bank; teachers must prepare and ask questions verbally$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$No analytics or exportable reports on student performance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Limited to a single 'buzzer' game format rather than varied quiz types$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Primarily documented and supported in French, which may limit non-French-speaking adoption$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Is Digibuzzer free to use?$q$, $q$Yes. Digibuzzer is entirely free, with no paid plan, subscription, or watermark.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Do students need to create an account?$q$, $q$No. Students join a game room with just a nickname and optional avatar; no email or password is required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Who makes Digibuzzer?$q$, $q$Digibuzzer is published by La Digitale, a French collective of free, open, and privacy-respecting education tools founded by Emmanuel Zimmert.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Can Digibuzzer be used for remote learning?$q$, $q$Yes. Because it runs entirely in a browser, students can join a game session from home over a shared link just as easily as in a physical classroom.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Does Digibuzzer store student data?$q$, $q$No persistent personal data is required or stored; game sessions are hosted on GDPR-compliant Swiss servers and are ephemeral.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$What is Digidrive and do I need it for Digibuzzer?$q$, $q$Digidrive is an optional, donation-funded content dashboard across La Digitale's tools; it is not required to create or run Digibuzzer games.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Live classroom quiz review$q$, $q$Teachers use Digibuzzer to gamify end-of-lesson or end-of-unit review sessions with fast-paced, verbally-asked questions.$q$, $q$K-12 and higher-education teachers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Corporate and continuing-education training games$q$, $q$Trainers use the buzzer format to reinforce learning checkpoints in workshops and professional development sessions.$q$, $q$Corporate trainers and continuing-education instructors$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited game rooms","No account required for students","Live buzzer scoring and leaderboard","GDPR-compliant hosting"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Digibuzzer is a free online buzzer-quiz game built by La Digitale, a French collective of privacy-first, open education tools. It turns any classroom into a live game-show set: the teacher hosts a session, students join instantly from a phone or tablet with just a nickname, and whoever buzzes in first gets a shot at answering a question the teacher asks out loud.$q$, $q$There is no question bank to configure and no account to create for either the teacher or the students, which makes Digibuzzer one of the fastest live-quiz tools to set up when you just want to gamify a review session or oral practice on short notice.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Digibuzzer's feature set is intentionally narrow: create a game room, share a join link or code, let students pick a name and avatar, and run a 'first buzz wins' round where the teacher judges each answer live and the app keeps score automatically with a running leaderboard or podium.$q$, $q$Because sessions are stored temporarily on GDPR-compliant, Swiss-hosted infrastructure (Infomaniak) and no personal data is required from students, Digibuzzer is frequently recommended in French education circles as a data-minimal alternative to commercial gamified-quiz platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Digibuzzer is completely free with no paid plan, seat limit, or watermark. The wider La Digitale project is sustained through voluntary donations via Open Collective, and the only optional paid add-on across the whole tool suite is Digidrive, a content-management dashboard unlocked through a donation-based invitation code - it is not required to use Digibuzzer.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('384faab2-7aa8-4e95-8df9-454c72ae8bb2', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Unlimited collaborative walls$q$, $q$Teachers can create as many pads as needed with no cap on the number of boards.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Multimedia capsules$q$, $q$Each post can contain text, images, audio, video, documents (up to 25 MB per file), or embedded links.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$No account required to post$q$, $q$Students and collaborators can contribute to a wall without signing up for an account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Write or read-only modes$q$, $q$Walls can be opened for open contribution or locked to teacher-only posting for curated resource sharing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Synchronous or asynchronous use$q$, $q$Works equally well for live in-class collaboration and take-home, self-paced resource review.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Easy link-based sharing$q$, $q$A pad is shared via a simple link or short code rather than an invite system.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$GDPR-compliant EU hosting$q$, $q$Content is hosted on Infomaniak's Swiss servers, aligned with European data-privacy standards.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Padlet-style familiarity$q$, $q$Interface conventions mirror well-known pinboard tools, reducing the learning curve for new users.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Completely free with no board or file-count limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$No account required for students to contribute$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Flexible for both live collaboration and curated resource pages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Privacy-respecting, GDPR-aligned hosting in the EU$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$25 MB per-file upload limit can be restrictive for large videos$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Lacks some of the polish and richer templates of commercial tools like Padlet$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$No built-in moderation tools beyond switching a wall to read-only$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Primarily documented in French, which can slow onboarding for non-French speakers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Is Digipad really free?$q$, $q$Yes. Digipad has no paid tier; wall creation, posting, and file uploads up to 25 MB are all free.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$How is Digipad different from Padlet?$q$, $q$Digipad offers unlimited free walls and account-free participation, while Padlet limits free accounts to a small number of boards and requires payment for unlimited use.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Do students need an account to post on a Digipad wall?$q$, $q$No. Students can contribute using just the shared link, without creating an account.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$What file types can be added to a Digipad wall?$q$, $q$Text, images, audio, video, documents, and links to websites or interactive content, with a 25 MB limit per file.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Who develops Digipad?$q$, $q$Digipad is developed by La Digitale, an independent French education-tools initiative founded by Emmanuel Zimmert in 2020.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Where is Digipad's data hosted?$q$, $q$On Infomaniak's Swiss servers, chosen for GDPR-aligned, European data-residency compliance.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Flipped-classroom resource hub$q$, $q$Teachers curate links, files, and videos on a read-only pad for students to review before class.$q$, $q$K-12 and higher-education teachers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Collaborative brainstorming wall$q$, $q$Students post ideas, notes, and media to a shared pad during group work or peer review activities.$q$, $q$Students and classroom groups$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited pads","Files up to 25 MB each","No account required to post","Write and read-only modes"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Digipad is a free collaborative wall tool from La Digitale that functions much like Padlet: teachers create a shared 'pad,' share a link, and participants post text, files, images, audio, video, or links onto it - live during class or asynchronously over time.$q$, $q$Unlike most commercial pinboard tools, Digipad does not require participants to create an account to post, and it places no limit on the number of pads a teacher can create or files they can attach, making it a popular free alternative in budget-constrained education settings.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Each Digipad wall is made of individual capsules that can hold files up to 25 MB, formatted text, or embedded links to videos and websites, and walls can be switched between open 'write' mode and curated 'read-only' mode depending on the activity.$q$, $q$Because no account is required to contribute, Digipad lowers participation barriers for shy students and works equally well for synchronous, in-class collaboration and asynchronous, take-home resource sharing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Digipad is entirely free, with unlimited walls and no feature-gated paid tier. The only optional paid layer in the La Digitale ecosystem is Digidrive, a donation-unlocked content-management dashboard that is not required to create or use Digipad walls.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa1eddeb-7917-4f4d-ba86-efb4ac29e2dc', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Live single/multi-choice polls$q$, $q$Create instant polls that display aggregated results in real time as participants respond.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Digital brainstorming boards$q$, $q$Collect free-form ideas from participants on a shared virtual board during a session.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Real-time word clouds$q$, $q$Generate live word clouds from participant text submissions to visualize common themes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Live quizzes$q$, $q$Run quick comprehension checks with instant scoring during a lesson or training.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Code-based, account-free joining$q$, $q$Participants join with a simple code or link, with no registration required.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$No participant or response caps$q$, $q$Unlike freemium competitors, Digistorm places no limit on class size or number of activities.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$GDPR-aligned EU hosting$q$, $q$Activity data is hosted on Infomaniak's Swiss servers rather than U.S.-based ad-tech infrastructure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Part of the La Digitale suite$q$, $q$Works alongside sibling tools Digipad, Digiwall, and Digibuzzer for broader interactive lesson planning.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Completely free with no participant or usage caps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$No account required for participants to respond$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Combines polling, brainstorming, word clouds, and quizzes in one tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Privacy-first, GDPR-aligned hosting with no ad tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Fewer visual themes and customization options than commercial tools like Mentimeter$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$No built-in analytics history or long-term reporting dashboard$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Primarily documented and supported in French$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Lacks integrations with presentation software like PowerPoint or Google Slides$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Is Digistorm free to use?$q$, $q$Yes. Digistorm has no paid tier and places no limit on the number of participants or activities.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Do participants need to create an account?$q$, $q$No. Participants join a poll, brainstorm, or quiz using a code or link, with no sign-up required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$What activity types does Digistorm support?$q$, $q$Single- and multiple-choice polls, digital brainstorming boards, live word clouds, and real-time quizzes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$How does Digistorm compare to Mentimeter or Slido?$q$, $q$Digistorm offers similar live-polling and brainstorming features for free with no response caps, whereas Mentimeter and Slido limit free usage and charge for full functionality.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Who builds Digistorm?$q$, $q$Digistorm is built by La Digitale, an independent French education-tools initiative founded by Emmanuel Zimmert.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Where is Digistorm's data stored?$q$, $q$On Infomaniak's Swiss servers, in line with GDPR data-residency practices used across La Digitale's tools.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Live lecture engagement$q$, $q$Instructors run quick polls and quizzes during a lecture to check understanding in real time.$q$, $q$University lecturers and classroom teachers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Workshop brainstorming sessions$q$, $q$Facilitators collect and visualize ideas from participants using the brainstorming and word-cloud modes.$q$, $q$Trainers and workshop facilitators$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited polls, brainstorms, word clouds and quizzes","No participant sign-up required","Live, real-time results visualization","GDPR-compliant hosting"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Digistorm is a free, all-in-one live-engagement tool from La Digitale that combines polls, brainstorming boards, word clouds, and real-time quizzes into a single application teachers can launch instantly for a class, lecture, or training session.$q$, $q$Participants join with a code or link and respond without creating an account, with results - vote counts, word-cloud visualizations, or idea walls - updating live on the host's screen as responses come in.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Digistorm supports single- and multiple-choice polling with instant results, a digital sticky-note-style brainstorming mode for open idea collection, live word clouds generated from participant text submissions, and real-time quizzes for comprehension checks.$q$, $q$All activities can be created and joined without an account, and data is hosted on GDPR-aligned Swiss infrastructure, making it attractive for schools with strict student-data-privacy requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Digistorm is entirely free with no participant limits, response caps, or paid feature tiers, unlike commercial competitors such as Mentimeter or Slido that gate usage behind freemium limits. The only optional paid add-on across La Digitale's suite is Digidrive, a donation-unlocked content dashboard that is not required to use Digistorm.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36a13fec-4212-4e84-87b2-11cac8bee967', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Droplets (virtual servers)$q$, $q$Linux-based cloud VMs that provision in under a minute, billed per second with predictable flat pricing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$DigitalOcean Kubernetes$q$, $q$A managed Kubernetes service with a free control plane and pay-as-you-go worker nodes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$App Platform$q$, $q$A Git-connected PaaS that automatically builds and deploys applications on every code push.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Managed Databases$q$, $q$Fully managed PostgreSQL, MySQL, Redis/Valkey, MongoDB, and Kafka clusters with automated backups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Spaces object storage$q$, $q$S3-compatible object storage bundled with a built-in CDN for static assets and backups.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$GPU Droplets$q$, $q$On-demand GPU compute for AI training and inference workloads, billed hourly.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Load balancers and VPC networking$q$, $q$Traffic distribution and private networking to build resilient, secure multi-server architectures.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$REST API and Terraform support$q$, $q$Full programmatic control over infrastructure for automation and infrastructure-as-code workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Simple, predictable, transparent per-resource pricing versus hyperscalers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Fast provisioning and a developer-friendly control panel and API$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Extensive, widely cited community tutorial library for Linux and web-hosting topics$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Broad product range (compute, Kubernetes, databases, storage, GPU) without AWS-level complexity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$No permanent free tier for compute resources$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Fewer global data-center regions and enterprise compliance certifications than AWS, Azure, or GCP$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Advanced enterprise features (fine-grained IAM, extensive compliance tooling) are less mature than hyperscalers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Can become less cost-competitive at very large scale compared to negotiated hyperscaler enterprise contracts$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$How much does DigitalOcean cost?$q$, $q$Droplets start at $4/month, App Platform at $5/month, managed databases around $15/month, and Kubernetes worker nodes from about $12/month, all billed on a usage basis.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Is DigitalOcean good for beginners?$q$, $q$Yes. DigitalOcean is widely regarded as one of the most approachable cloud providers for individual developers due to its simple pricing, fast setup, and extensive community documentation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Is DigitalOcean publicly traded?$q$, $q$Yes. DigitalOcean went public on the NYSE in March 2021 under the ticker symbol DOCN.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$What is DigitalOcean's main competitor?$q$, $q$Linode (Akamai), Vultr, and Hetzner are its closest simplified-cloud competitors, while AWS, Google Cloud, and Azure compete for larger, more complex workloads.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Does DigitalOcean offer managed Kubernetes?$q$, $q$Yes, DigitalOcean Kubernetes offers a free control plane with pay-as-you-go worker node pricing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Does DigitalOcean support GPU workloads for AI?$q$, $q$Yes, GPU Droplets provide on-demand GPU compute for AI training and inference, billed hourly.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Startup and indie developer hosting$q$, $q$Small teams and solo developers host production web apps and APIs without a dedicated DevOps team.$q$, $q$Startups and independent developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Agency client hosting$q$, $q$Digital agencies deploy and manage multiple client websites and applications on predictable, flat-rate infrastructure.$q$, $q$Digital agencies and freelance developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$AI/ML training and inference$q$, $q$Teams use GPU Droplets to train and serve machine learning models without committing to a hyperscaler's GPU pricing.$q$, $q$AI/ML engineers and data science teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Droplets$q$, $q$From $4/month$q$, $q$Usage-based (per second)$q$, NULL, $q$["Linux virtual servers","Provision in under a minute","Scalable CPU/RAM/storage configurations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$App Platform$q$, $q$From $5/month$q$, $q$Usage-based$q$, NULL, $q$["Git-connected automatic deploys","Managed SSL and scaling","Static site hosting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Managed Databases$q$, $q$From $15/month$q$, $q$Usage-based$q$, NULL, $q$["PostgreSQL, MySQL, Redis/Valkey, MongoDB, Kafka","Automated backups","High-availability options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$GPU Droplets$q$, $q$From ~$2.50/hour$q$, $q$Usage-based (hourly)$q$, NULL, $q$["On-demand GPU compute","AI training and inference workloads","Multiple GPU configurations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DigitalOcean is a publicly traded (NYSE: DOCN) cloud infrastructure provider founded in 2011 and headquartered in New York City, built around the idea that cloud computing should be simple, predictable, and accessible to individual developers and small teams rather than only large enterprises.$q$, $q$Its core product, the Droplet virtual server, along with managed Kubernetes, App Platform, managed databases, object storage, and GPU compute, competes with AWS, Google Cloud, and Azure by trading deep configurability for flat pricing and a much smaller, more approachable set of options.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DigitalOcean's flagship product is the Droplet, a Linux virtual machine that spins up in under a minute and is billed by the second with a 60-second minimum; the platform also offers managed Kubernetes, a Git-connected App Platform PaaS, managed database clusters, S3-compatible Spaces object storage, and GPU Droplets for AI workloads.$q$, $q$All services are accessible through a unified control panel, REST API, CLI, and Terraform provider, and DigitalOcean's community tutorial library is one of the most widely cited general-purpose sysadmin and web-hosting knowledge bases on the internet.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DigitalOcean uses pure usage-based pricing with no mandatory subscription: Droplets start at 4 dollars per month, App Platform at 5 dollars per month, Kubernetes worker nodes from roughly 12 dollars per month (control plane free), managed databases from about 15 dollars per month, and GPU Droplets around 2.50 dollars per hour, with new sign-ups often eligible for promotional trial credit.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Photo-gallery capsules$q$, $q$Display multiple images together in a single capsule, useful for photo-essay or documentation activities.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Image-with-audio capsules$q$, $q$Pair a picture with a recorded or uploaded audio clip in one combined post.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Account-free contribution$q$, $q$Participants can post to a Digiwall board without creating an account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Open-source codebase$q$, $q$Source code is published publicly on Codeberg for transparency and community contribution.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Link-based board sharing$q$, $q$Boards are created and shared with a simple link rather than an invite system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Text, file, and link capsules$q$, $q$Supports the same core capsule types as Digipad alongside its newer media formats.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$GDPR-aligned hosting$q$, $q$Data is hosted on European infrastructure consistent with La Digitale's privacy-first approach.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Part of the La Digitale suite$q$, $q$Complements sibling tools Digipad, Digistorm, and Digibuzzer for broader classroom activity design.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Completely free with an openly published, auditable codebase$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$No account required for participants to contribute$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Richer media capsule types (gallery, image+audio) than Digipad$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Privacy-first, GDPR-aligned hosting with no ad tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Less widely documented and reviewed than its sibling tool Digipad$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Primarily supported and documented in French$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Smaller feature set than fully commercial pinboard tools like Padlet$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$No formal enterprise support or SLA, being a community-maintained project$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Is Digiwall free to use?$q$, $q$Yes, Digiwall is entirely free with an openly published codebase and no paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$How is Digiwall different from Digipad?$q$, $q$Digiwall is an evolution of Digipad that adds new capsule formats, including photo galleries and combined image-with-audio posts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Is Digiwall open source?$q$, $q$Yes, its source code is published on Codeberg under the ladigitale/digiwall repository.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Do participants need an account to use Digiwall?$q$, $q$No, participants can contribute to a Digiwall board without creating an account.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Who develops Digiwall?$q$, $q$Digiwall is developed by La Digitale, an independent French education-tools initiative founded by Emmanuel Zimmert.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$What is Digidrive and is it required for Digiwall?$q$, $q$Digidrive is an optional, donation-funded content dashboard across La Digitale's tools; it is not required to create or use Digiwall boards.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Photo-essay and documentation projects$q$, $q$Students compile image galleries with narration to document a project or field trip.$q$, $q$K-12 and higher-education teachers and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Oral-language and portfolio walls$q$, $q$Teachers use image-with-audio capsules for language practice or student portfolio narration.$q$, $q$Language teachers and portfolio-based courses$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited boards","Photo-gallery and image+audio capsules","No account required to post","Open-source codebase"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Digiwall is a free, open-source collaborative multimedia wall from La Digitale, built as an evolution of the collective's earlier Digipad tool. It keeps the same shared-board concept but adds new capsule types, including a photo-gallery format and a combined image-with-audio format for richer, media-based collaboration.$q$, $q$Like other La Digitale tools, Digiwall requires no account for contributors, and its source code is published openly on Codeberg, making it one of the more transparently auditable tools in the La Digitale suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Digiwall boards are made of capsules that can hold text, files, links, image galleries, or combined image-and-audio posts, letting teachers run visually and audibly rich collaborative activities that go beyond Digipad's simpler capsule set.$q$, $q$Boards can be shared via a link with no participant sign-up required, and content is hosted on GDPR-aligned European infrastructure consistent with the rest of the La Digitale suite.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Digiwall is completely free and open source, with no feature paywall. The only paid add-on across La Digitale's ecosystem is Digidrive, a donation-unlocked content dashboard that is optional and not required to use Digiwall.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08388501-9b47-462d-b036-ddaf4b02c5a5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Zero-configuration installation$q$, $q$Drop the files onto a PHP-capable web server and the directory listing works immediately with no database setup.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Light and dark themes$q$, $q$Switch between visual themes to match personal or brand preference.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Built-in file search$q$, $q$Visitors can quickly search for specific files within large directory trees.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Custom sort ordering$q$, $q$Site owners control how files and folders are ordered in the listing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$File hashes for verification$q$, $q$Cryptographic hashes are displayed alongside downloads so users can verify file integrity.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$One-click zip downloads$q$, $q$Visitors can download an entire folder of files as a single compressed archive.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Multi-lingual support$q$, $q$The interface can be presented in a visitor's preferred language.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Composer/Packagist distribution$q$, $q$Available as the phlak/directory-lister package for developers integrating it into larger PHP projects.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Completely free, MIT-licensed, and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$No database or complex setup required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Actively maintained with a structured release history$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Lightweight, single-purpose, and fast to deploy on any PHP host$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Requires PHP 8.2 or higher as of the latest major version, which can exclude very old hosting environments$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$No built-in user accounts or access-control system for restricting who can view files$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Limited to file browsing rather than full file management, syncing, or collaboration$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Relies on self-hosting, so users are responsible for their own server security and updates$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Is Directory Lister free?$q$, $q$Yes. Directory Lister is free and open source under the MIT License with no paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$What are the requirements to run Directory Lister?$q$, $q$A PHP-capable web server; the latest major version (5.0.0) requires PHP 8.2 or higher.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Do I need a database to use Directory Lister?$q$, $q$No, Directory Lister reads directly from the filesystem and requires no database.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Who maintains Directory Lister?$q$, $q$It is created and maintained by developer Chris Kankiewicz (PHLAK) with contributions from the open-source community.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Can I use Directory Lister for a commercial project?$q$, $q$Yes, its MIT License permits free use, modification, and redistribution, including in commercial contexts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$How is Directory Lister different from a web server's built-in directory listing?$q$, $q$It adds search, themes, custom sorting, file hashes, and zip downloads that basic Apache or Nginx autoindexing does not provide.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Software release archive hosting$q$, $q$Open-source projects use it to expose a browsable folder of release builds or downloads.$q$, $q$Open-source maintainers and developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Client deliverable sharing$q$, $q$Agencies and freelancers share files or project exports with clients via a simple browsable link.$q$, $q$Agencies and freelance web developers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$Free / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted on any PHP-capable server","No database required","Full feature set with no paywall","MIT License"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Directory Lister is a free, open-source, self-hosted PHP script that turns any web-accessible folder into a clean, browsable file-listing page with a zero-configuration, drag-and-drop installation.$q$, $q$Maintained by developer Chris Kankiewicz (PHLAK) and the open-source community under the MIT License, it requires no database and runs on any standard PHP-capable web host, making it a lightweight alternative to full cloud file-sharing platforms for simply exposing a folder's contents.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Directory Lister includes light and dark themes, custom sort ordering, built-in file search, cryptographic file hashes for download verification, one-click zip downloads of entire directories, and multi-lingual interface support.$q$, $q$Because it reads directly from the filesystem, any files added, removed, or renamed in the configured folder appear in the listing immediately with no manual re-indexing required.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Directory Lister is completely free and open source under the MIT License, with no paid tier, subscription, or enterprise plan; the only cost is the PHP-capable web hosting a user already has. Voluntary financial support for the maintainer is accepted via GitHub Sponsors.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7970f696-afb2-4a60-a110-66287a0c9216', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Database-first architecture$q$, $q$Connects to an existing SQL database and generates APIs without requiring a proprietary schema or data migration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Instant REST and GraphQL APIs$q$, $q$Automatically exposes CRUD endpoints in both REST and GraphQL based on the connected database's structure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$No-code admin Studio$q$, $q$A visual interface for managing content, collections, and users without writing code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Role-based access control$q$, $q$Granular permissions system for controlling who can read, write, or manage specific data and fields.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Flows automation builder$q$, $q$A visual workflow engine for triggering webhooks, emails, and data transformations based on events.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$AI assistant and MCP server$q$, $q$Built-in AI tooling for content authoring plus a native Model Context Protocol server for AI agent integration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Self-hosting or managed cloud$q$, $q$Deploy on your own infrastructure for free or use Directus's managed cloud hosting on paid plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$SSO support$q$, $q$SAML and OIDC single sign-on available on Team and Enterprise plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Free self-hosting with no proprietary data lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Works over an existing SQL database rather than requiring a migration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Generates both REST and GraphQL APIs automatically$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$No-code admin panel usable by non-developers alongside a full API for developers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Licensed under a source-available license (MSCL) rather than a fully permissive open-source license$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Cloud and Team pricing ($499+/month) is significant for smaller teams needing hosted support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Collection and flow limits on lower tiers can require an upgrade as projects grow$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Learning curve for teams unfamiliar with database-first (versus schema-first) CMS concepts$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Is Directus free to use?$q$, $q$Yes, the Core plan is free for self-hosting with 3 seats, 25 collections, and 5 flows; organizations under $5M in revenue may also qualify for the free or discounted Open Innovation Grant.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$What databases does Directus support?$q$, $q$PostgreSQL, MySQL, SQL Server, SQLite, and other SQL-compatible database engines.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Is Directus open source?$q$, $q$Directus is source-available under the Monospace Sustainable Core License (MSCL) 1.0, which permits free self-hosting and commercial use for most organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Who owns Directus?$q$, $q$Directus is developed and maintained by Monospace Inc., headquartered in Brooklyn, New York.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Does Directus support GraphQL as well as REST?$q$, $q$Yes, Directus automatically generates both REST and GraphQL APIs from the connected database schema.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$What is Directus's Open Innovation Grant?$q$, $q$A program offering free self-hosted access or discounted cloud hosting to organizations under roughly $5 million in annual revenue.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Custom backend for web and mobile apps$q$, $q$Developers use Directus to add instant APIs and an admin panel on top of a production database.$q$, $q$Developers and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Enterprise data platform and internal tools$q$, $q$Organizations use Directus to build internal admin panels and data management tools without vendor lock-in.$q$, $q$Enterprises and IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Agency client CMS projects$q$, $q$Agencies deploy Directus as a flexible, white-label headless CMS for client websites and apps.$q$, $q$Digital agencies and freelance developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Core$q$, $q$Free$q$, $q$N/A (self-hosted; cloud add-on $99/month)$q$, NULL, $q$["3 user seats","25 collections","5 flows","AI assistant","Advanced RBAC","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Team$q$, $q$$499/month (annual) or $599/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["10 SSO seats","50-100 collections","20 flows","SAML/OIDC SSO","Included cloud hosting","Basic support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["200+ collections","Unlimited flows","Custom LLM integration","Offline mode","AI translations","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$Open Innovation Grant$q$, $q$Free (self-hosted) or $99/month (cloud)$q$, $q$N/A / Monthly$q$, NULL, $q$["For organizations under $5M annual revenue and under 50 employees","Full feature access with no artificial limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Directus is an open-source, self-hostable data platform that turns any existing SQL database into a headless CMS, instantly generating REST and GraphQL APIs plus a no-code admin Studio for managing content, users, and permissions.$q$, $q$Originally rooted in a Flash-based database tool from 2004, Directus was rebuilt from the ground up in 2019 into the modern, database-first headless CMS now maintained by Monospace Inc., a company headquartered in Brooklyn, New York.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Directus connects directly to PostgreSQL, MySQL, SQL Server, SQLite, and other SQL databases without requiring a data migration, and layers on role-based access control, Flows for workflow automation, an AI assistant, and a native MCP server for AI agent integration.$q$, $q$Because it wraps around a database a team already controls rather than owning a proprietary data store, organizations can adopt or remove Directus without losing or reformatting their underlying data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Directus offers a free self-hosted Core plan (3 seats, 25 collections, 5 flows), a Team plan at $499-$599/month with SSO and included cloud hosting, custom Enterprise pricing, and a free or discounted Open Innovation Grant tier for organizations under $5M in annual revenue.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a106a741-e518-4de4-ace7-f5c84db01f4a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
