INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Fully branded native apps$q$, $q$Launch your own iOS and Android app in the App Store and Google Play under your own brand, not Disciple's.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Discussion groups$q$, $q$Create multiple groups to segment community conversations by topic, tier, or cohort.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Live and on-demand video$q$, $q$Host livestreams and video events, including multi-host livestreams on higher-tier plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Monetizable courses$q$, $q$Build and sell online courses directly within the branded community app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$0% transaction fees$q$, $q$Disciple does not take a cut of member subscription or course revenue processed on the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Direct messaging$q$, $q$Members can message each other directly within the branded app.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Advanced analytics$q$, $q$Track community engagement and membership metrics on Plus and Pro tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$API access and Zapier integration$q$, $q$Connect Disciple to other tools and automate workflows on higher-tier plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Fully white-labeled, independently app-store-listed iOS and Android apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$0% transaction fees on member and course revenue across all plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Combines community, courses, and livestreaming in a single platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$No coding required to launch and configure the app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Entry pricing starts at $399/month, higher than many community-platform alternatives$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Admin seats, groups, and video minutes are capped on lower tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Monetizable courses require the Plus tier or above$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Custom Organisation-tier pricing is not publicly listed, requiring a sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$How much does Disciple cost?$q$, $q$Plans start at $399/month billed annually (Branded App) and go up to $999/month (Branded App Pro), with a custom-priced Organisation tier for enterprises.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Does Disciple take a cut of my revenue?$q$, $q$No, Disciple applies a 0% transaction fee policy across all plans; customers keep the revenue they collect, subject to standard payment-processing fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Do I get a real iOS and Android app?$q$, $q$Yes, every plan includes a fully branded native app listed in the Apple App Store and Google Play Store, plus a web version.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Who founded Disciple?$q$, $q$Disciple was founded around 2013 by Benji Vaughan and Jeremy Smith in London.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Can I sell courses through Disciple?$q$, $q$Yes, monetizable courses are available starting on the Branded App Plus plan and above.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$What is the difference between Disciple Media and Disciple?$q$, $q$Disciple is the current brand name for the platform formerly marketed as Disciple Media; disciplemedia.com now redirects to disciple.community.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Creator and coaching membership communities$q$, $q$Coaches and creators launch a branded app combining paid courses, group discussion, and livestreams for their audience.$q$, $q$Coaches, creators, and membership businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Brand and fan communities$q$, $q$Brands and artists build a dedicated, ad-free space for fans and customers separate from mainstream social platforms.$q$, $q$Brands, artists, and publishers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Branded App$q$, $q$$399/month (annual) or $469/month (quarterly)$q$, $q$Annual or quarterly$q$, NULL, $q$["Unlimited members","2 admin seats","5 groups","1 non-monetizable course","5,000 video minutes"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Branded App Plus$q$, $q$$599/month (annual) or $699/month (quarterly)$q$, $q$Annual or quarterly$q$, NULL, $q$["No Disciple branding","5 admin seats","10 groups","1 monetizable course","10,000 video minutes","Custom domain","Advanced analytics","Zapier integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Branded App Pro$q$, $q$$999/month (annual) or $1,169/month (quarterly)$q$, $q$Annual or quarterly$q$, NULL, $q$["Unlimited admin seats","Unlimited groups","Unlimited monetized courses","20,000 video minutes","API access","Multi-host livestreams","Multi-tier member pricing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$Organisation$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Bespoke feature development","Dedicated strategy sessions","Migration support","Custom security options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Disciple, formerly Disciple Media, is a London-based platform that lets creators, coaches, and brands build a fully white-labeled community app for iOS, Android, and web, complete with groups, courses, livestreams, and monetization, without writing code.$q$, $q$Founded around 2013 by Benji Vaughan and Jeremy Smith out of a desire to give musicians a direct, algorithm-free way to connect with fans, the company shifted from a bespoke app-development agency into a self-service SaaS platform starting around 2016.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every Disciple plan includes a fully branded native iOS and Android app plus a web version, with tools for discussion groups, direct messaging, live and on-demand video, monetizable online courses, and event hosting.$q$, $q$Disciple applies a 0% transaction fee policy across all plans, meaning customers keep the revenue they collect from members and courses, subject only to standard payment-processing fees.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0754695b-69c5-4fc3-ae4a-a24cfa640353', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Disciple's plans range from Branded App at $399/month (annual billing) up to Branded App Pro at $999/month, with a custom-priced Organisation tier for large enterprises; higher tiers add more admin seats, groups, monetizable courses, video minutes, API access, and multi-host livestreams.$q$]::text[], 2);
